                LastName = "Student",
                EnrollmentDate = System.DateTime.Parse("2023-01-01")
            };

            // Act
            context.Students.Add(student);
            context.SaveChanges();

            // Assert
            var retrieved = context.Students.Single(s => s.LastName == "Student");
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
