            context.Courses.Add(course);
            context.SaveChanges();

            // Assert
            var retrieved = context.Courses.Single(c => c.CourseID == 9999);
            Assert.Equal("Test Course", retrieved.Title);
            Assert.Equal(3, retrieved.Credits);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            DbInitializer.Initialize(context);

            // Act — verify composite key works (CourseID + InstructorID)
            var assignments = context.CourseAssignments.ToList();

            // Assert
            Assert.True(assignments.Count > 0);
            // Each combination of CourseID+InstructorID should be unique
            var distinctKeys = assignments.Select(a => new { a.CourseID, a.InstructorID }).Distinct().Count();
            Assert.Equal(assignments.Count, distinctKeys);
        }

        [Fact]
