                StartDate = System.DateTime.Parse("2023-06-01")
            };

            // Act
            context.Departments.Add(department);
            context.SaveChanges();

            // Assert
            var retrieved = context.Departments.Single(d => d.Name == "Physics");
            Assert.Equal(200000, retrieved.Budget);
        }

        [Fact]
        public void SchoolContext_CanAddEnrollmentWithRelationships()
        {
            // Arrange
            using var context = TestDbContextFactory.Create();
            var student = new Student
            {
                FirstMidName = "Enroll",
                LastName = "Test",
                EnrollmentDate = System.DateTime.Parse("2023-01-01")
            };
            context.Students.Add(student);

            var dept = new Department
            {
                Name = "TestDept",
                Budget = 50000,
                StartDate = System.DateTime.Parse("2023-01-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 8888,
                Title = "Enrollment Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
