using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_ValidInputs_SetsProperties()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 2, 3);

            // Assert
            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, list.Count);
            Assert.Equal("a", list[0]);
            Assert.Equal("b", list[1]);
            Assert.Equal("c", list[2]);
        }

        [Theory]
        [InlineData(10, 3, 4)]   // ceil(10/3) = 4
        [InlineData(9, 3, 3)]    // ceil(9/3) = 3
        [InlineData(1, 10, 1)]   // ceil(1/10) = 1
        [InlineData(0, 5, 0)]    // ceil(0/5) = 0
        [InlineData(100, 10, 10)]
        public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Theory]
        [InlineData(1, false)]  // first page — no previous
        [InlineData(2, true)]   // second page — has previous
        [InlineData(3, true)]
        public void HasPreviousPage_VariousPageIndexes_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

            // Assert
            Assert.Equal(expected, list.HasPreviousPage);
        }

        [Theory]
        [InlineData(1, 3, true)]   // page 1 of 3 — has next
        [InlineData(3, 3, false)]  // page 3 of 3 — no next
        [InlineData(2, 3, true)]
        public void HasNextPage_VariousPageIndexes_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            // Arrange — totalPages = ceil(count/pageSize)
            int pageSize = 10;
            int count = totalPages * pageSize;

            // Act
            var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

            // Assert
            Assert.Equal(expected, list.HasNextPage);
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result[0]);
            Assert.Equal(10, result[9]);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 10);

            // Assert
            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
            Assert.Equal(25, result[4]);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_MiddlePage_SkipsAndTakesCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 30).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 10);

            // Assert
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
            Assert.True(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }
    }
}

