        [Fact]
        public void Index_WithInstructorIdAndCourseId_PopulatesEnrollments()
        {
            // Arrange
            var instructor = _context.Instructors.First(i =>
                i.CourseAssignments != null && i.CourseAssignments.Any());
            var courseAssignment = instructor.CourseAssignments.First();
            var courseId = courseAssignment.CourseID;

            // Act
