using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            // Act
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Contains("Student 'John Doe'", notification.Message);
            Assert.Contains("has been created", notification.Message);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            // Act
            _service.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Course (ID: 42)", notification.Message);
            Assert.Contains("has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            // Act
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("has been deleted", notification.Message);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Act
            var result = _service.ReceiveNotification();

            // Assert
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFOOrder()
        {
            // Arrange
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            // Act & Assert
            Assert.Equal("A", _service.ReceiveNotification()!.EntityType);
            Assert.Equal("B", _service.ReceiveNotification()!.EntityType);
            Assert.Equal("C", _service.ReceiveNotification()!.EntityType);
            Assert.Null(_service.ReceiveNotification());
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "has been created")]
        [InlineData(EntityOperation.UPDATE, "has been updated")]
        [InlineData(EntityOperation.DELETE, "has been deleted")]
        public void SendNotification_AllOperations_GeneratesCorrectVerb(EntityOperation operation, string expectedVerb)
        {
            // Act
            _service.SendNotification("Entity", "1", "Test", operation);

            // Assert
            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedVerb, notification!.Message);
        }
    }
}

