            {
                FirstMidName = "Delete",
                LastName = "Me",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;
            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.DoesNotContain(_context.Instructors, i => i.ID == instructor.ID);
        }

        [Fact]
        public void DeleteConfirmed_InstructorWithDepartment_NullsDepartmentAdministrator()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Admin",
                LastName = "Removal",
                HireDate = DateTime.Parse("2023-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
