    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextFactory.Create();
            _controller = new NotificationsController(_context);
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
            // Drain any leftover notifications from static queue
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void GetNotifications_NoNotifications_ReturnsEmptySuccessResult()
        {
            var result = _controller.GetNotifications() as JsonResult;
            Assert.NotNull(result);
            dynamic value = result.Value!;
            var type = value.GetType();
            Assert.True((bool)type.GetProperty("success")!.GetValue(value));
            Assert.Equal(0, (int)type.GetProperty("count")!.GetValue(value));
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            var svc = new NotificationService();
            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "Admin");

            var result = _controller.GetNotifications() as JsonResult;
            Assert.NotNull(result);
            dynamic value = result.Value!;
            var type = value.GetType();
            Assert.True((bool)type.GetProperty("success")!.GetValue(value));
            Assert.Equal(2, (int)type.GetProperty("count")!.GetValue(value));
        }

        [Fact]
        public void GetNotifications_LimitsToTen()
        {
            var svc = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            var result = _controller.GetNotifications() as JsonResult;
            Assert.NotNull(result);
            dynamic value = result.Value!;
            var type = value.GetType();
            Assert.Equal(10, (int)type.GetProperty("count")!.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_ReturnsSuccessResult()
        {
            var result = _controller.MarkAsRead(1) as JsonResult;
            Assert.NotNull(result);
            dynamic value = result.Value!;
            var type = value.GetType();
            Assert.True((bool)type.GetProperty("success")!.GetValue(value));
        }
    }
}

