+            var type = value.GetType();
+            Assert.True((bool)type.GetProperty("success")!.GetValue(value));
+            Assert.Equal(0, (int)type.GetProperty("count")!.GetValue(value));
+        }
+
+        [Fact]
+        public void GetNotifications_WithNotifications_ReturnsNotifications()
+        {
